import{_ as i,o as t,c as l,ag as r}from"./chunks/framework.DXGyWiRo.js";const a="/images/lekt2601.jpg",n="/images/lekt2602.jpg",b=JSON.parse('{"title":"Lektion 26","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion26.md","filePath":"lektionen/lektion26.md"}'),s={name:"lektionen/lektion26.md"};function u(o,e,d,h,c,m){return t(),l("div",null,[...e[0]||(e[0]=[r('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-26" tabindex="-1">Lektion 26 <a class="header-anchor" href="#lektion-26" aria-label="Permalink to &quot;Lektion 26&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>26.1. Cerebralisationsgesetz für -s- im Wortinnern</li><li>26.2. Cerebralisationsgesetz für Dentale im Wortinnern</li><li>26.3. Wortsandhi für Palatal, Guttural, ṣ, h + -s</li><li>26.4. Grassmannsches Hauchdissimilationsgesetz</li><li>26.5. Wortsandhi für -m, -n vor Zischlaut</li><li>26.6. Gebrauch des einfachen Futurs (ऌत्, भविष्यन्ती f.)</li><li>26.7. Bildung des einfachen Futurs (ऌत्, भविष्यन्ती  f.)</li><li>26.8. Übung</li></ul><p>Zur Bildung des einfachen Futurs (ऌत्) benötigen wir noch folgende Gesetze des Wortsandhi:</p><h2 id="_26-1-cerebralisationsgesetz-fur-s-im-wortinnern" tabindex="-1">26.1. Cerebralisationsgesetz für -s- im Wortinnern <a class="header-anchor" href="#_26-1-cerebralisationsgesetz-fur-s-im-wortinnern" aria-label="Permalink to &quot;26.1. Cerebralisationsgesetz für -s- im Wortinnern&quot;">​</a></h2><p>-s- wird durch -ṣ- ersetzt, wenn k, r, l oder ein Vokal - außer a, ā - unmittelbar oder nur durch अनुस्वार oder विसर्ग getrennt vorausgeht und ein anderer Laut als ṛ, r folgt.</p><p>Diesem Sandhi folgt auch दुस्- vor tonlosen Gutturalen und Labialen in Komposita.</p><p>Beispiel:</p><blockquote><p>तेषाम् (aus: te-sām)</p><p>aber:</p><p>तासाम् (tā-sām)</p></blockquote><h2 id="_26-2-cerebralisationsgesetz-fur-dentale-im-wortinnern" tabindex="-1">26.2. Cerebralisationsgesetz für Dentale im Wortinnern <a class="header-anchor" href="#_26-2-cerebralisationsgesetz-fur-dentale-im-wortinnern" aria-label="Permalink to &quot;26.2. Cerebralisationsgesetz für Dentale im Wortinnern&quot;">​</a></h2><p>Dentale Versclusslaute werden nach Retroflexen (inklusive -ṣ-) durch die entsprechenden Retroflexe ersetzt:</p><ul><li>iṣ + -ta  = इष्ट</li><li>ti + sth +a + ti = तिष्ठति (ṣ wegen des vorangehenden i, ṭh wegen des dann vorausgehenden ṣ)</li></ul><h2 id="_26-3-wortsandhi-fur-palatal-guttural-s-h-s" tabindex="-1">26.3. Wortsandhi für Palatal, Guttural, ṣ, h + -s <a class="header-anchor" href="#_26-3-wortsandhi-fur-palatal-guttural-s-h-s" aria-label="Permalink to &quot;26.3. Wortsandhi für Palatal, Guttural, ṣ, h + -s&quot;">​</a></h2><p>-k, -kh, -g, -gh; -c, -j; -ś, -ṣ; -h + s- » -kṣ<br> Beispiele siehe unten</p><h2 id="_26-4-grassmannsches-hauchdissimilationsgesetz" tabindex="-1">26.4. Grassmannsches Hauchdissimilationsgesetz <a class="header-anchor" href="#_26-4-grassmannsches-hauchdissimilationsgesetz" aria-label="Permalink to &quot;26.4. Grassmannsches Hauchdissimilationsgesetz&quot;">​</a></h2><p>Eine unmittelbare Folge zweier Aspirata (Aspirata - Vokal - Aspirata) hat den Verlust der Behauchung des ersten Lautes zur Folge:<br> Beispiel:<br> *dhu(gh) » du(g)h<br> Verliert infolge von Lautgesetzen der zweite Laut seine Behauchung, so tritt die Behauchung wieder beim ersten Laut auf.<br> Beispiele: siehen unten Futur von दुह् und  बुध्</p><p><img src="'+a+'" alt=""><br> Abb.: Hermann Graßmann (1809 - 1877)<br> Mathematiker und Indologe</p><h2 id="_26-5-wortsandhi-fur-m-n-vor-zischlaut" tabindex="-1">26.5. Wortsandhi für -m, -n vor Zischlaut <a class="header-anchor" href="#_26-5-wortsandhi-fur-m-n-vor-zischlaut" aria-label="Permalink to &quot;26.5. Wortsandhi für -m, -n vor Zischlaut&quot;">​</a></h2><p>Vor Zischlauten werden -n und -m durch -ṃ- ersetzt:<br> Beispiel: s. unten Futur von मन्</p><h2 id="_26-6-gebrauch-des-einfachen-futurs-ऌत्-भविष्यन्ती-f" tabindex="-1">26.6. Gebrauch des einfachen Futurs (ऌत्, भविष्यन्ती f.) <a class="header-anchor" href="#_26-6-gebrauch-des-einfachen-futurs-ऌत्-भविष्यन्ती-f" aria-label="Permalink to &quot;26.6. Gebrauch des einfachen Futurs (ऌत्, भविष्यन्ती f.)&quot;">​</a></h2><p>Das Einfache Futur (ऌत्, भविष्यन्ती f.) drückt aus</p><ul><li>die Zukunft</li><li>eine beabsichtigte oder gewollte Handlung (&quot;ich werde gehen&quot;, &quot;ich will gehen&quot;)</li><li>eine Erwartung (&quot;es wird so geschehen&quot;)</li><li>Hoffnung</li><li>Befürchtung</li><li>Wahrscheinlichkeit</li><li>Meinung des Sprechenden</li><li>Befehl</li></ul><p>Das Futur steht teilweise in Konkurrenz zum Optativ (siehe später).<br> z. B.<br> व्रतं करिष्यन्देवगृहं गच्छति = &quot;Jemand, der ein Gelübde zu machen wünscht, geht zum Tempel,.&quot;</p><p><img src="'+n+'" alt=""><br> Abb.: व्रतं करिष्यन्देवगृहं गच्छति<br> Hampi = ಹಂಪೆ<br> [Bildquelle: mattlogelin. -- <a href="http://www.flickr.com/photos/mattlogelin/159113586/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/mattlogelin/159113586/</a>. -- Zugriff am 2008-12-18. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung)]</p><h2 id="_26-7-bildung-des-einfachen-futurs-ऌत्-भविष्यन्ती-f" tabindex="-1">26.7. Bildung des einfachen Futurs (ऌत्, भविष्यन्ती  f.) <a class="header-anchor" href="#_26-7-bildung-des-einfachen-futurs-ऌत्-भविष्यन्ती-f" aria-label="Permalink to &quot;26.7. Bildung des einfachen Futurs (ऌत्, भविष्यन्ती  f.)&quot;">​</a></h2><p>Einfaches Futur:<br> Futursstamm + Primärendung</p><p>Futurstamm:<br> (meist) hochstufige Wurzel + -sya<br> oder<br> (meist) hochstufige Wurzel + -i- + -sya (= - iṣya)<br> Welche Wurzel welche Bildung des Futurstamms hat, muss man mit den Stammformen lernen!<br> Im Allgemeinen stimmt Wurzelform und Bindevokal des Futurs mit dem Infinitiv überein.<br> Manche Wurzeln können das Futur optionell mit und ohne Bindevokal -i- bilden.<br> Das Partizip Parasmaipada des Futurs wird durch Anfügen des Suffixes -nt- an den Futurstamm gebildet, Femininum fakultativ auf -ntī oder -tī:</p><blockquote><p>क्रृ :  करिष्यन्त्, करिष्यन्ती / करिष्यती</p></blockquote><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th>Wurzel</th><th>Futur 3. sg. P (Ā)</th></tr></thead><tbody><tr><td>नी</td><td>नेष्यति</td></tr><tr><td>भू</td><td>भविष्यति (भो +  इ + स्य + ति)</td></tr><tr><td>दिश्</td><td>देक्ष्यति (देश् + स्य + ति)</td></tr><tr><td>द्र्श्</td><td>द्रक्ष्यति</td></tr><tr><td>पच्</td><td>पक्ष्यति</td></tr><tr><td>प्रच्छ्</td><td>प्रक्ष्यति</td></tr><tr><td>यज्</td><td>यक्ष्यत्</td></tr><tr><td>सृज्</td><td>स्रक्ष्यति</td></tr><tr><td>पद्</td><td>पत्स्यति</td></tr><tr><td>अद्</td><td>अत्स्यति</td></tr><tr><td>दुह्</td><td>धोक्ष्यति (दोघ् +  स्य + ति)</td></tr><tr><td>बुध्</td><td>भोत्स्यते (बोध् vor Stimmlosem = भोत्</td></tr><tr><td>मन्</td><td>मंस्यते (मन् + स्य + ते)</td></tr></tbody></table></blockquote><h2 id="_26-8-ubung" tabindex="-1">26.8. Übung <a class="header-anchor" href="#_26-8-ubung" aria-label="Permalink to &quot;26.8. Übung&quot;">​</a></h2><p>Bilden Sie die in Zahl, Person und Genus verbi (Parasmaipada, Ātmanepada) entsprechenden Futurformen:</p><p>A) ohne Bindevokal -i-:</p><ol><li>अत्ति</li><li>प्राप्नुवन्ति</li><li>सम्यन्ति</li><li>विजयन्ते</li><li>दहन्</li><li>आदिशन्ति</li><li>दोग्धि</li><li>पश्यति (Futur von दृश् bilden)</li><li>उपानयन्ति</li><li>पचति</li><li>उपपद्यन्ते</li><li>पिबति</li><li>पृच्छति</li><li>बुध्यन्ते</li><li>मन्यते</li><li>मुञ्चति</li><li>यजते</li><li>युध्यन्ते</li><li>भजति</li><li>कृषति</li><li>क्रुध्यन्ति</li><li>दुष्यति</li><li>द्वेष्टि</li><li>पान्ति</li><li>सीदति</li><li>लभते</li><li>वक्ति</li><li>प्रविशन्ति</li><li>शक्नोति</li><li>शृणोति</li><li>सिञ्चति</li><li>सुन्वन्ति</li><li>सृजति</li><li>स्तौति</li><li>तिष्ठति</li></ol><p>B) Mit Bindevokal -i-:</p><ol><li>अस्यति</li><li>आसते</li><li>इच्छति</li><li>संस्करोति</li><li>खादति</li><li>लुभ्यति</li><li>तनुते</li><li>उपागच्छन्ति</li><li>चरति</li><li>जायन्ते</li><li>नृत्यति</li><li>सहते</li><li>पतन्ति</li><li>रोदिति</li><li>प्रभवति</li><li>म्रियन्ते (im Futur Parasmaipada)</li><li>जीवन्ति</li><li>रक्षति</li><li>वदति</li><li>स्मरति</li><li>घ्नन्ति</li><li>अर्हन्ति</li><li>कुप्यन्ति</li></ol><p>C) Futur optionell mit und ohne -i-:</p><ol><li>मुह्यन्ति</li><li>वर्तते</li><li>अश्नुवते (im Futur Parasmaipada)</li></ol>',39)])])}const f=i(s,[["render",u]]);export{b as __pageData,f as default};
